import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { Eye, EyeOff } from 'lucide-react';
import { themes } from '../styles/theme';

const RegisterPage = () => {
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  
  const { register } = useAuth();
  const toast = useToast();
  const navigate = useNavigate();

  // Use dark theme by default - Finify emerald colors
  const theme = themes.dark;

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!formData.name || !formData.email || !formData.password) {
      toast.error('Please fill in all fields');
      return;
    }

    setLoading(true);
    try {
      await register(formData);
      toast.success('Account created successfully!');
      navigate('/login');
    } catch (error) {
      toast.error(error.response?.data?.detail || 'Registration failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const styles = {
    container: { 
      minHeight: '100vh', 
      display: 'flex', 
      alignItems: 'center', 
      justifyContent: 'center', 
      padding: '1rem',
      backgroundColor: theme['--bg-main']
    },
    card: { 
        width: '100%', 
        maxWidth: '420px', 
        padding: '2.5rem', 
        backgroundColor: '#141414', 
        borderRadius: '16px', 
        border: `1px solid ${theme['--surface-border']}`, 
        boxShadow: theme['--shadow-elevated']
    },
    title: { 
      fontFamily: 'system-ui, sans-serif', 
      fontSize: '2rem', 
      fontWeight: '700',
      color: theme['--accent-primary'], 
      marginBottom: '0.5rem', 
      textAlign: 'center' 
    },
    subtitle: {
      color: theme['--text-muted'],
      textAlign: 'center',
      marginBottom: '2rem',
      fontSize: '0.875rem'
    },
    inputGroup: { position: 'relative', marginBottom: '1.2rem', width: '100%' },
    label: {
      display: 'block',
      color: theme['--text-secondary'],
      fontSize: '0.75rem',
      fontWeight: '600',
      marginBottom: '0.5rem',
      textTransform: 'uppercase',
      letterSpacing: '0.05em'
    },
    input: { 
        width: '100%', 
        padding: '0.875rem 1rem',
        backgroundColor: theme['--input-bg'], 
        border: `1px solid ${theme['--input-border']}`, 
        borderRadius: '8px', 
        color: theme['--text-primary'], 
        fontSize: '0.95rem', 
        outline: 'none',
        boxSizing: 'border-box',
        transition: 'border-color 0.2s, box-shadow 0.2s'
    },
    toggleBtn: { 
        position: 'absolute', 
        right: '12px', 
        top: '60%', 
        transform: 'translateY(-50%)', 
        background: 'none', 
        border: 'none', 
        color: theme['--text-muted'], 
        cursor: 'pointer', 
        display: 'flex', 
        alignItems: 'center',
        zIndex: 10,
        fontSize: '1rem'
    },
    button: { 
        width: '100%', 
        padding: '0.875rem', 
        marginTop: '0.5rem', 
        backgroundColor: theme['--accent-primary'], 
        color: '#000', 
        border: 'none', 
        borderRadius: '8px', 
        fontSize: '1rem',
        fontWeight: '600',
        cursor: 'pointer',
        transition: 'background-color 0.2s, transform 0.1s'
    },
    link: {
      color: theme['--accent-primary'],
      textDecoration: 'none',
      fontWeight: '500'
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h2 style={styles.title}>Finify</h2>
        <p style={styles.subtitle}>Create your account</p>
        
        <form onSubmit={handleSubmit}>
          
          <div style={styles.inputGroup}>
            <label style={styles.label}>Full Name</label>
            <input 
                type="text"
                placeholder="John Doe"
                value={formData.name}
                onChange={(e) => setFormData({...formData, name: e.target.value})}
                style={styles.input}
                required
            />
          </div>
          
          <div style={styles.inputGroup}>
            <label style={styles.label}>Email</label>
            <input 
                type="email"
                placeholder="you@example.com"
                value={formData.email}
                onChange={(e) => setFormData({...formData, email: e.target.value})}
                style={styles.input}
                required
            />
          </div>
          
          <div style={styles.inputGroup}>
            <label style={styles.label}>Password</label>
            <input 
                type={showPassword ? "text" : "password"}
                placeholder="Create a password"
                value={formData.password}
                onChange={(e) => setFormData({...formData, password: e.target.value})}
                style={styles.input}
                required
            />
            <button type="button" onClick={() => setShowPassword(!showPassword)} style={styles.toggleBtn}>
              {showPassword ? <FaEyeSlash /> : <FaEye />}
            </button>
          </div>
          
          <button type="submit" style={styles.button} disabled={loading}>
            {loading ? 'Creating account...' : 'Create Account'}
          </button>
        </form>
        
        <div style={{textAlign: 'center', marginTop: '1.5rem'}}>
            <Link to="/login" style={styles.link}>Already have an account? Sign in</Link>
        </div>
      </div>
    </div>
  );
};
export default RegisterPage;
